<span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">    PRIVATE</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> Qt6::Quick Qt6::Core</span></span>
